          this.updateCanvasSize();
          
          // 스케일바 모드이고 아직 감지되지 않은 경우 스케일바 감지 실행
          if (this.scaleMethod === 'scaleBar' && !this.scaleBarDetected) {
            this.detectScaleBar();
